#include <omp.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <sys/time.h>

#include "./main.h"

#define fp float

#ifdef RD_WG_SIZE_0_0
        #define NUMBER_THREADS RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
        #define NUMBER_THREADS RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
        #define NUMBER_THREADS RD_WG_SIZE
#else
        #define NUMBER_THREADS 256
#endif

void extract_kernel(long d_Ne, fp* d_I) {
    #pragma omp parallel for
    for (long ei = 0; ei < d_Ne; ei++) {
        d_I[ei] = exp(d_I[ei]/255);
    }
}

void prepare_kernel(long d_Ne, fp* d_I, fp* d_sums, fp* d_sums2) {
    #pragma omp parallel for
    for (long ei = 0; ei < d_Ne; ei++) {
        d_sums[ei] = d_I[ei];
        d_sums2[ei] = d_I[ei]*d_I[ei];
    }
}

void reduce_kernel(long d_Ne, long d_no, int d_mul, fp* d_sums, fp* d_sums2, int gridDim) {
    int nf = NUMBER_THREADS - (gridDim * NUMBER_THREADS - d_no);
    int df = 0;

    fp d_psum[NUMBER_THREADS];
    fp d_psum2[NUMBER_THREADS];

    #pragma omp parallel for
    for (int tx = 0; tx < NUMBER_THREADS; tx++) {
        d_psum[tx] = 0;
        d_psum2[tx] = 0;
    }

    #pragma omp parallel for
    for (int tx = 0; tx < NUMBER_THREADS; tx++) {
        long ei = tx;
        if (ei < d_no) {
            d_psum[tx] = d_sums[ei * d_mul];
            d_psum2[tx] = d_sums2[ei * d_mul];
        }
    }

    #pragma omp barrier

    if (nf == NUMBER_THREADS) {
        for (int i = 2; i <= NUMBER_THREADS; i = 2 * i) {
            #pragma omp parallel for
            for (int tx = 0; tx < NUMBER_THREADS; tx++) {
                if ((tx + 1) % i == 0) {
                    d_psum[tx] = d_psum[tx] + d_psum[tx - i/2];
                    d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i/2];
                }
            }
            #pragma omp barrier
        }

        d_sums[0] = d_psum[NUMBER_THREADS - 1];
        d_sums2[0] = d_psum2[NUMBER_THREADS - 1];
    }
    else {
        if (gridDim > 1) {
            for (int i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                #pragma omp parallel for
                for (int tx = 0; tx < NUMBER_THREADS; tx++) {
                    if ((tx + 1) % i == 0) {
                        d_psum[tx] = d_psum[tx] + d_psum[tx - i/2];
                        d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i/2];
                    }
                }
                #pragma omp barrier
            }

            d_sums[0] = d_psum[NUMBER_THREADS - 1];
            d_sums2[0] = d_psum2[NUMBER_THREADS - 1];
        }
        else {
            for (int i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                if (i <= nf) {
                    df = i;
                }
            }

            for (int i = 2; i <= df; i = 2 * i) {
                #pragma omp parallel for
                for (int tx = 0; tx < NUMBER_THREADS; tx++) {
                    if ((tx + 1) % i == 0 && tx < df) {
                        d_psum[tx] = d_psum[tx] + d_psum[tx - i/2];
                        d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i/2];
                    }
                }
                #pragma omp barrier
            }

            fp local_sum = d_psum[df - 1];
            fp local_sum2 = d_psum2[df - 1];
            for (long i = df; i < nf; i++) {
                local_sum += d_sums[i];
                local_sum2 += d_sums2[i];
            }

            d_sums[0] = local_sum;
            d_sums2[0] = local_sum2;
        }
    }
}

void srad_kernel(fp d_lambda, int d_Nr, int d_Nc, long d_Ne, int* d_iN, int* d_iS, int* d_jE, int* d_jW, fp* d_dN, fp* d_dS, fp* d_dW, fp* d_dE, fp d_q0sqr, fp* d_c, fp* d_I) {
    #pragma omp parallel for
    for (long ei = 0; ei < d_Ne; ei++) {
        int row;
        int col;

        fp d_Jc;
        fp d_dN_loc, d_dS_loc, d_dW_loc, d_dE_loc;
        fp d_c_loc;
        fp d_G2, d_L, d_num, d_den, d_qsqr;

        row = (ei + 1) % d_Nr - 1;
        col = (ei + 1) / d_Nr + 1 - 1;
        if ((ei + 1) % d_Nr == 0) {
            row = d_Nr - 1;
            col = col - 1;
        }

        if (ei < d_Ne) {
            d_Jc = d_I[ei];

            d_dN_loc = d_I[d_iN[row] + d_Nr * col] - d_Jc;
            d_dS_loc = d_I[d_iS[row] + d_Nr * col] - d_Jc;
            d_dW_loc = d_I[row + d_Nr * d_jW[col]] - d_Jc;
            d_dE_loc = d_I[row + d_Nr * d_jE[col]] - d_Jc;

            d_G2 = (d_dN_loc * d_dN_loc + d_dS_loc * d_dS_loc + d_dW_loc * d_dW_loc + d_dE_loc * d_dE_loc) / (d_Jc * d_Jc);

            d_L = (d_dN_loc + d_dS_loc + d_dW_loc + d_dE_loc) / d_Jc;

            d_num = (0.5 * d_G2) - ((1.0 / 16.0) * (d_L * d_L));
            d_den = 1 + (0.25 * d_L);
            d_qsqr = d_num / (d_den * d_den);

            d_den = (d_qsqr - d_q0sqr) / (d_q0sqr * (1 + d_q0sqr));
            d_c_loc = 1.0 / (1.0 + d_den);

            if (d_c_loc < 0) {
                d_c_loc = 0;
            }
            else if (d_c_loc > 1) {
                d_c_loc = 1;
            }

            d_dN[ei] = d_dN_loc;
            d_dS[ei] = d_dS_loc;
            d_dW[ei] = d_dW_loc;
            d_dE[ei] = d_dE_loc;
            d_c[ei] = d_c_loc;
        }
    }
}

void srad2_kernel(fp d_lambda, int d_Nr, int d_Nc, long d_Ne, int* d_iN, int* d_iS, int* d_jE, int* d_jW, fp* d_dN, fp* d_dS, fp* d_dW, fp* d_dE, fp* d_c, fp* d_I) {
    #pragma omp parallel for
    for (long ei = 0; ei < d_Ne; ei++) {
        int row;
        int col;

        fp d_cN, d_cS, d_cW, d_cE;
        fp d_D;

        row = (ei + 1) % d_Nr - 1;
        col = (ei + 1) / d_Nr + 1 - 1;
        if ((ei + 1) % d_Nr == 0) {
            row = d_Nr - 1;
            col = col - 1;
        }

        if (ei < d_Ne) {
            d_cN = d_c[ei];
            d_cS = d_c[d_iS[row] + d_Nr * col];
            d_cW = d_c[ei];
            d_cE = d_c[row + d_Nr * d_jE[col]];

            d_D = d_cN * d_dN[ei] + d_cS * d_dS[ei] + d_cW * d_dW[ei] + d_cE * d_dE[ei];

            d_I[ei] = d_I[ei] + 0.25 * d_lambda * d_D;
        }
    }
}

void compress_kernel(long d_Ne, fp* d_I) {
    #pragma omp parallel for
    for (long ei = 0; ei < d_Ne; ei++) {
        d_I[ei] = log(d_I[ei]) * 255;
    }
}

void kernel_gpu_opencl_wrapper(fp* image, int Nr, int Nc, long Ne, int niter, fp lambda, long NeROI, int* iN, int* iS, int* jE, int* jW, int iter, int mem_size_i, int mem_size_j) {
#ifdef TIMING
    struct timeval tv;
    struct timeval tv_total_start, tv_total_end;
    struct timeval tv_init_end;
    struct timeval tv_h2d_start, tv_h2d_end;
    struct timeval tv_d2h_start, tv_d2h_end;
    struct timeval tv_kernel_start, tv_kernel_end;
    struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
    struct timeval tv_close_start, tv_close_end;
    float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0, d2h_time = 0, close_time = 0, total_time = 0;

    gettimeofday(&tv_total_start, NULL);
#endif

    fp* d_I = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_iN = (fp*)malloc(sizeof(fp) * mem_size_i);
    fp* d_iS = (fp*)malloc(sizeof(fp) * mem_size_i);
    fp* d_jE = (fp*)malloc(sizeof(fp) * mem_size_j);
    fp* d_jW = (fp*)malloc(sizeof(fp) * mem_size_j);
    fp* d_dN = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_dS = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_dW = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_dE = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_c = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_sums = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_sums2 = (fp*)malloc(sizeof(fp) * Ne);

    int* d_iN_int = (int*)malloc(sizeof(int) * mem_size_i);
    int* d_iS_int = (int*)malloc(sizeof(int) * mem_size_i);
    int* d_jE_int = (int*)malloc(sizeof(int) * mem_size_j);
    int* d_jW_int = (int*)malloc(sizeof(int) * mem_size_j);

    memcpy(d_I, image, sizeof(fp) * Ne);
    memcpy(d_iN_int, iN, sizeof(int) * mem_size_i);
    memcpy(d_iS_int, iS, sizeof(int) * mem_size_i);
    memcpy(d_jE_int, jE, sizeof(int) * mem_size_j);
    memcpy(d_jW_int, jW, sizeof(int) * mem_size_j);

#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_init_end, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
#endif

    int blocks_x = Ne / NUMBER_THREADS;
    if (Ne % NUMBER_THREADS != 0) {
        blocks_x += 1;
    }

    int blocks_work_size = blocks_x;

    fp total;
    fp total2;
    fp meanROI;
    fp meanROI2;
    fp varROI;
    fp q0sqr;

    printf("max # of workgroups = %d, # of threads/workgroup = %d (ensure that device can handle)\n", blocks_x, NUMBER_THREADS);

#ifdef TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

    extract_kernel(Ne, d_I);

    fp d_q0sqr;

    printf("Iterations Progress: hidden\n");

    for (iter = 0; iter < niter; iter++) {
        fflush(NULL);

        prepare_kernel(Ne, d_I, d_sums, d_sums2);

        int blocks2_work_size = blocks_work_size;
        long no = Ne;
        int mul = 1;

        while (blocks2_work_size != 0) {
            reduce_kernel(Ne, no, mul, d_sums, d_sums2, blocks2_work_size);

            no = blocks2_work_size;
            if (blocks2_work_size == 1) {
                blocks2_work_size = 0;
            }
            else {
                mul = mul * NUMBER_THREADS;
                blocks_x = blocks2_work_size / NUMBER_THREADS;
                if (blocks2_work_size % NUMBER_THREADS != 0) {
                    blocks_x = blocks_x + 1;
                }
                blocks2_work_size = blocks_x;
            }
        }

        total = d_sums[0];
        total2 = d_sums2[0];

        meanROI = total / (fp)(NeROI);
        meanROI2 = meanROI * meanROI;
        varROI = (total2 / (fp)(NeROI)) - meanROI2;
        q0sqr = varROI / meanROI2;

        d_q0sqr = q0sqr;

        srad_kernel(lambda, Nr, Nc, Ne, d_iN_int, d_iS_int, d_jE_int, d_jW_int, d_dN, d_dS, d_dW, d_dE, d_q0sqr, d_c, d_I);

        srad2_kernel(lambda, Nr, Nc, Ne, d_iN_int, d_iS_int, d_jE_int, d_jW_int, d_dN, d_dS, d_dW, d_dE, d_c, d_I);
    }

    printf("\n");

#ifdef TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
#endif

    compress_kernel(Ne, d_I);

#ifdef TIMING
    gettimeofday(&tv_d2h_start, NULL);
#endif

    memcpy(image, d_I, sizeof(fp) * Ne);

#ifdef TIMING
    gettimeofday(&tv_d2d_end, NULL);
    tvsub(&tv_d2h_end, &tv_d2h_start, &tv);
    d2h_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
#endif

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

    free(d_I);
    free(d_iN);
    free(d_iS);
    free(d_jE);
    free(d_jW);
    free(d_dN);
    free(d_dS);
    free(d_dW);
    free(d_dE);
    free(d_c);
    free(d_sums);
    free(d_sums2);
    free(d_iN_int);
    free(d_iS_int);
    free(d_jE_int);
    free(d_jW_int);

#ifdef TIMING
    printf("Time spent in different stages of the application:\n");
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif
}
